class ModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        
    def download_from_url(self, url: str, force_download: bool = False) -> str:
        url_hash = hashlib.md5(url.encode()).hexdigest()
        filename = f"model_{url_hash}.pth"
        filepath = self.cache_dir / filename
        
        if filepath.exists() and not force_download:
            print(f"Model already cached at {filepath}")
            return str(filepath)
        
        print(f"Downloading model from {url}...")
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        downloaded = 0
        
        with open(filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
                    downloaded += len(chunk)
                    if total_size > 0:
                        progress = (downloaded / total_size) * 100
                        print(f"\rProgress: {progress:.2f}%", end='')
        
        print(f"\nModel downloaded to {filepath}")
        return str(filepath)
    
    def load_checkpoint(self, path: str, map_location: str = 'cpu') -> Dict[str, Any]:
        print(f"Loading checkpoint from {path}...")
        checkpoint = torch.load(path, map_location=map_location)
        return checkpoint


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningPipeline:
    def __init__(self, model_name: str = 'resnet50', num_classes: int = 10, 
                 device: str = None):
        self.model_name = model_name
        self.num_classes = num_classes
        self.device = device if device else ('cuda' if torch.cuda.is_available() else 'cpu')
        self.model = None
        self.optimizer = None
        self.criterion = nn.CrossEntropyLoss()
        
    def load_pretrained_model(self, pretrained: bool = True):
        print(f"Loading pretrained {self.model_name}...")
        
        if self.model_name == 'resnet50':
            self.model = models.resnet50(pretrained=pretrained)
            num_features = self.model.fc.in_features
            self.model.fc = nn.Linear(num_features, self.num_classes)
        elif self.model_name == 'resnet18':
            self.model = models.resnet18(pretrained=pretrained)
            num_features = self.model.fc.in_features
            self.model.fc = nn.Linear(num_features, self.num_classes)
        elif self.model_name == 'vgg16':
            self.model = models.vgg16(pretrained=pretrained)
            num_features = self.model.classifier[6].in_features
            self.model.classifier[6] = nn.Linear(num_features, self.num_classes)
        elif self.model_name == 'efficientnet_b0':
            self.model = models.efficientnet_b0(pretrained=pretrained)
            num_features = self.model.classifier[1].in_features
            self.model.classifier[1] = nn.Linear(num_features, self.num_classes)
        else:
            raise ValueError(f"Unsupported model: {self.model_name}")
        
        self.model = self.model.to(self.device)
        print(f"Model loaded and moved to {self.device}")
        
    def load_custom_checkpoint(self, checkpoint_path: str):
        checkpoint = torch.load(checkpoint_path, map_location=self.device)
        
        if 'model_state_dict' in checkpoint:
            state_dict = checkpoint['model_state_dict']
        elif 'state_dict' in checkpoint:
            state_dict = checkpoint['state_dict']
        else:
            state_dict = checkpoint
        
        try:
            self.model.load_state_dict(state_dict, strict=False)
            print("Checkpoint loaded successfully")
        except Exception as e:
            print(f"Warning: Could not load full checkpoint. Error: {e}")
            print("Attempting partial loading...")
            model_dict = self.model.state_dict()
            pretrained_dict = {k: v for k, v in state_dict.items() if k in model_dict and v.size() == model_dict[k].size()}
            model_dict.update(pretrained_dict)
            self.model.load_state_dict(model_dict)
            print(f"Loaded {len(pretrained_dict)}/{len(state_dict)} layers")
        
    def freeze_layers(self, freeze_until: Optional[str] = None):
        if freeze_until:
            freeze = True
            for name, param in self.model.named_parameters():
                if freeze_until in name:
                    freeze = False
                param.requires_grad = not freeze
        else:
            for param in self.model.parameters():
                param.requires_grad = False
            
            if self.model_name.startswith('resnet'):
                for param in self.model.fc.parameters():
                    param.requires_grad = True
            elif self.model_name == 'vgg16':
                for param in self.model.classifier[6].parameters():
                    param.requires_grad = True
            elif self.model_name.startswith('efficientnet'):
                for param in self.model.classifier.parameters():
                    param.requires_grad = True
        
        trainable_params = sum(p.numel() for p in self.model.parameters() if p.requires_grad)
        total_params = sum(p.numel() for p in self.model.parameters())
        print(f"Trainable parameters: {trainable_params:,} / {total_params:,}")
    
    def setup_optimizer(self, lr: float = 0.001, optimizer_type: str = 'adam'):
        if optimizer_type == 'adam':
            self.optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), lr=lr)
        elif optimizer_type == 'sgd':
            self.optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                      lr=lr, momentum=0.9)
        else:
            raise ValueError(f"Unsupported optimizer: {optimizer_type}")
    
    def train_epoch(self, dataloader: DataLoader):
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0
        
        for batch_idx, (inputs, labels) in enumerate(dataloader):
            inputs, labels = inputs.to(self.device), labels.to(self.device)
            
            self.optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = self.criterion(outputs, labels)
            loss.backward()
            self.optimizer.step()
            
            running_loss += loss.item()
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()
            
            if (batch_idx + 1) % 10 == 0:
                print(f'Batch [{batch_idx + 1}/{len(dataloader)}], '
                      f'Loss: {running_loss / (batch_idx + 1):.4f}, '
                      f'Acc: {100. * correct / total:.2f}%')
        
        epoch_loss = running_loss / len(dataloader)
        epoch_acc = 100. * correct / total
        return epoch_loss, epoch_acc
    
    def validate(self, dataloader: DataLoader):
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in dataloader:
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                outputs = self.model(inputs)
                loss = self.criterion(outputs, labels)
                
                running_loss += loss.item()
                _, predicted = outputs.max(1)
                total += labels.size(0)
                correct += predicted.eq(labels).sum().item()
        
        val_loss = running_loss / len(dataloader)
        val_acc = 100. * correct / total
        return val_loss, val_acc
    
    def fine_tune(self, train_loader: DataLoader, val_loader: DataLoader = None,
                  epochs: int = 10, save_path: str = 'finetuned_model.pth'):
        print(f"\nStarting fine-tuning for {epochs} epochs...")
        best_acc = 0.0
        
        for epoch in range(epochs):
            print(f'\nEpoch {epoch + 1}/{epochs}')
            print('-' * 50)
            
            train_loss, train_acc = self.train_epoch(train_loader)
            print(f'Training - Loss: {train_loss:.4f}, Acc: {train_acc:.2f}%')
            
            if val_loader:
                val_loss, val_acc = self.validate(val_loader)
                print(f'Validation - Loss: {val_loss:.4f}, Acc: {val_acc:.2f}%')
                
                if val_acc > best_acc:
                    best_acc = val_acc
                    self.save_model(save_path, epoch, val_acc)
                    print(f'Best model saved with accuracy: {best_acc:.2f}%')
        
        print(f'\nFine-tuning completed. Best validation accuracy: {best_acc:.2f}%')
    
    def save_model(self, path: str, epoch: int = None, accuracy: float = None):
        checkpoint = {
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': self.optimizer.state_dict() if self.optimizer else None,
            'model_name': self.model_name,
            'num_classes': self.num_classes,
            'epoch': epoch,
            'accuracy': accuracy
        }
        torch.save(checkpoint, path)
        print(f"Model saved to {path}")


def create_dummy_dataset(num_samples: int = 1000, num_classes: int = 10, 
                         img_size: int = 224):
    data = torch.randn(num_samples, 3, img_size, img_size)
    labels = torch.randint(0, num_classes, (num_samples,))
    return data, labels


